import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Button, Card, Chip, icon } from 'decantr/components';

code.example:
function KanbanBoard({ columns }) {
  const { div, span, h3 } = tags;

  return div({ class: css('_flex _gap4 _overflow[auto] _pb4 _flex1') },
    ...columns.map(col =>
      div({ class: css('_flex _col _gap3 _minW[280px] _w[320px] _flexShrink0') },
        div({ class: css('_flex _aic _jcsb _px2') },
          div({ class: css('_flex _aic _gap2') },
            span({ class: css('_w[8px] _h[8px] _rfull') }),
            h3({ class: css('_textsm _bold') }, col.title),
            Badge({ variant: 'outline', size: 'sm' }, `${col.items.length}`)
          ),
          Button({ variant: 'ghost', size: 'sm' }, icon('plus', { size: '1em' }))
        ),
        div({ class: css('_flex _col _gap2') },
          ...col.items.map(item =>
            Card({ hover: true, class: css('_cursor[pointer]') },
              Card.Body({ class: css('_flex _col _gap2 _p3') },
                div({ class: css('_flex _aic _jcsb') },
                  span({ class: css('_textsm _bold') }, item.title),
                  Badge({ variant: item.priority === 'high' ? 'error' : item.priority === 'medium' ? 'warning' : 'default', size: 'sm' }, item.priority)
                ),
                span({ class: css('_textxs _fgmuted _lineClamp2') }, item.description),
                div({ class: css('_flex _aic _jcsb _mt1') },
                  Chip({ label: item.assignee, size: 'xs' }),
                  span({ class: css('_textxs _fgmuted') }, item.date)
                )
              )
            )
          )
        )
      )
    )
  );
}
